#include <algorithm>

using namespace std;



int N, C, A[6], bc[1 << 5];

int P[333], Q[333], M[1<<5][1<<5], V;

long long prv[333][333];

long long nxt[333][333];



int main()

{

	scanf("%d %d", &N, &C);

	for (int i = 0; i < N; i++) scanf("%d", &A[i]);

	sort(A, A + N);



	int b = (1 << (N - 1));

	prv[0][A[N - 1] * N] = nxt[0][A[N - 1] * N] = 1;

	for (int i = 1; i < b; i++) bc[i] = bc[i - (i&(-i))] + 1;

	for (int i = 0; i < b; i++) for (int j = 0; j < b; j++) if (bc[i] == bc[j]) {

		P[V] = i; Q[V] = j;

		M[i][j] = V++;

	}

	for (int t = 0; t < N*C; t++) {

		for (int i = 0; i < V; i++) {

			int p = P[i], q = Q[i], d = t % N - 1;

			if (d < 0 || (q & (1 << d))) continue;

			for (int k = t; k <= N*C; k++) if (prv[i][k]) {

				for (int j = 0; j < N-1; j++) if (~p & (1 << j)) {

					int x = min(N*C, max(k, t + A[j] * N));

					nxt[M[p + (1 << j)][q + (1 << d)]][x] += prv[i][k];

				}

			}

		}

		for (int i = 0; i < V; i++) for (int k = 0; k <= N*C; k++) prv[i][k] = nxt[i][k];

	}



	double ans = prv[V-1][N*C];

	for (int i = 1; i < N; i++) {

		ans /= i;

		ans /= C;

	}



	printf("%.16lf\n", ans);



	return 0;

}

